import numpy as np

def select_next_node(current_node, truck_nodes, destination_node, unvisited_nodes, distance_matrix):
    min_distance = np.inf
    next_node = None

    for node in unvisited_nodes:
        if distance_matrix[current_node][node] < min_distance:
            if node not in truck_nodes or node == destination_node:
                next_node = node
                min_distance = distance_matrix[current_node][node]

    if next_node is None:
        for node in unvisited_nodes:
            if distance_matrix[current_node][node] + distance_matrix[node][destination_node] < min_distance:
                if node not in truck_nodes:
                    next_node = node
                    min_distance = distance_matrix[current_node][node] + distance_matrix[node][destination_node]

    return next_node
